contracts/BaserootMarketplace.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract BaserootMarketplace is Ownable, ReentrancyGuard {
    struct Agent {
        uint256 id;
        address payable creator;
        uint256 price; // In Wei (AVAX)
        string metadata; // IPFS Hash or URL
        bool isActive;
        string[] datasetIds; // For Data Provenance
    }

    struct Dataset {
        string id;
        address payable provider; // DAO or Data Provider Wallet
        uint256 pricePerUse; // In Wei (AVAX) - Optional usage fee
        bool isActive;
    }

    uint256 public agentCount;
    uint256 public platformFeePercent = 10; // 10%
    
    mapping(uint256 => Agent) public agents;
    mapping(string => Dataset) public datasets; // Map ID string to Dataset struct

    event AgentRegistered(uint256 indexed agentId, address indexed creator, uint256 price, string metadata);
    event AgentUpdated(uint256 indexed agentId, uint256 price, string metadata, bool isActive);
    event DatasetRegistered(string indexed datasetId, address indexed provider, uint256 price);
    event ServicePaid(uint256 indexed agentId, address indexed user, uint256 amount, uint256 creditId);
    event PlatformFeeUpdated(uint256 newFeePercent);

    constructor(address initialOwner) Ownable(initialOwner) {}

    function registerAgent(
        uint256 _price, 
        string memory _metadata,
        string[] memory _datasetIds
    ) external returns (uint256) {
        agentCount++;
        uint256 newAgentId = agentCount;

        agents[newAgentId] = Agent({
            id: newAgentId,
            creator: payable(msg.sender),
            price: _price,
            metadata: _metadata,
            isActive: true, // Active by default
            datasetIds: _datasetIds
        });

        emit AgentRegistered(newAgentId, msg.sender, _price, _metadata);
        return newAgentId;
    }

    function updateAgent(uint256 _agentId, uint256 _price, string memory _metadata, bool _isActive) external {
        require(agents[_agentId].creator == msg.sender, "Only creator can update agent");
        
        Agent storage agent = agents[_agentId];
        agent.price = _price;
        agent.metadata = _metadata;
        agent.isActive = _isActive;

        emit AgentUpdated(_agentId, _price, _metadata, _isActive);
    }

    function registerDataset(string memory _datasetId, uint256 _pricePerUse) external {
        datasets[_datasetId] = Dataset({
            id: _datasetId,
            provider: payable(msg.sender),
            pricePerUse: _pricePerUse,
            isActive: true
        });

        emit DatasetRegistered(_datasetId, msg.sender, _pricePerUse);
    }

    // Main payment function
    function payForService(uint256 _agentId) external payable nonReentrant {
        Agent storage agent = agents[_agentId];
        require(agent.isActive, "Agent is not active");
        require(msg.value >= agent.price, "Insufficient payment");

        // Calculate Splits
        uint256 total = msg.value;
        uint256 platformFee = (total * platformFeePercent) / 100;
        uint256 creatorShare = total - platformFee;

        // Dataset Providers Share (Simplified: If datasets have prices, deduct from creator share or charge extra?)
        // For simplicity in this version, datasets are paid OUT of the remaining 90%, 
        // OR we can assume dataset cost is included in price.
        // Let's implement a simple model: Data Providers get a fixed cut if defined, otherwise 0.
        // But iterating array for payments costs gas. 
        // For verifyUsage/Provenance, we just emit the event so off-chain verifiers can track usage.
        
        // Transfer Platform Fee
        (bool successPlatform, ) = payable(owner()).call{value: platformFee}("");
        require(successPlatform, "Platform fee transfer failed");

        // Transfer Creator Share
        (bool successCreator, ) = agent.creator.call{value: creatorShare}("");
        require(successCreator, "Creator share transfer failed");

        // Generate a pseudo-random Credit ID for off-chain tracking
        uint256 creditId = uint256(keccak256(abi.encodePacked(msg.sender, _agentId, block.timestamp)));

        emit ServicePaid(_agentId, msg.sender, total, creditId);
    }

    function setPlatformFee(uint256 _percent) external onlyOwner {
        require(_percent <= 30, "Fee too high");
        platformFeePercent = _percent;
        emit PlatformFeeUpdated(_percent);
    }

    // Emergency withdraw
    function withdraw() external onlyOwner {
        payable(owner()).transfer(address(this).balance);
    }
}

